mapper.select:
SELECT c.id, c.contract_no AS contractNo, c.order_id AS orderId, o.order_no AS orderNo, c.customer_id AS customerId, cust.company_name AS customerName, c.contract_type AS contractType, CASE c.contract_type WHEN 'SALES' THEN '销售合同' WHEN 'PURCHASE' THEN '采购合同' WHEN 'AGENCY' THEN '代理合同' WHEN 'NDA' THEN '保密协议' ELSE c.contract_type END AS contractTypeDesc, c.contract_amount AS contractAmount, c.currency, c.sign_date AS signDate, c.start_date AS startDate, c.end_date AS endDate, c.status, CASE c.status WHEN 'DRAFT' THEN '草稿' WHEN 'PENDING_APPROVAL' THEN '待审批' WHEN 'APPROVED' THEN '已审批' WHEN 'REJECTED' THEN '已拒绝' WHEN 'ARCHIVED' THEN '已归档' WHEN 'CANCELLED' THEN '已取消' ELSE c.status END AS statusDesc, c.pdf_url AS pdfUrl, c.signed_url AS signedUrl, c.sales_id AS salesId, u.nickname AS salesName, c.approved_by AS approvedBy, approver.nickname AS approverName, c.approved_time AS approvedTime, c.created_by AS createdBy, creator.nickname AS createdByName, c.created_time AS createdTime, c.updated_time AS updatedTime, c.remark FROM crm_contract c LEFT JOIN crm_customer cust ON c.customer_id = cust.id AND cust.deleted = 0 LEFT JOIN crm_order o ON c.order_id = o.id AND o.deleted = 0 LEFT JOIN sys_user u ON c.sales_id = u.id LEFT JOIN sys_user approver ON c.approved_by = approver.id LEFT JOIN sys_user creator ON c.created_by = creator.id WHERE c.deleted = 0
AND c.contract_no LIKE CONCAT('%', #{query.contractNo}, '%')
AND c.contract_type = #{query.contractType}
AND cust.company_name LIKE CONCAT('%', #{query.customerName}, '%')
AND c.status = #{query.status}
AND c.sales_id = #{query.ownerId}
AND c.created_time >= #{query.startDate}
AND c.created_time <= #{query.endDate}
AND c.contract_amount >= #{query.minAmount}
AND c.contract_amount <= #{query.maxAmount}
ORDER BY c.created_time DESC

SELECT c.id, c.contract_no AS contractNo, o.order_no AS orderNo, cust.company_name AS customerName, CASE c.contract_type WHEN 'SALES' THEN '销售合同' WHEN 'PURCHASE' THEN '采购合同' WHEN 'AGENCY' THEN '代理合同' WHEN 'NDA' THEN '保密协议' ELSE c.contract_type END AS contractTypeDesc, c.contract_amount AS contractAmount, c.currency, c.sign_date AS signDate, c.start_date AS startDate, c.end_date AS endDate, CASE c.status WHEN 'DRAFT' THEN '草稿' WHEN 'PENDING_APPROVAL' THEN '待审批' WHEN 'APPROVED' THEN '已审批' WHEN 'REJECTED' THEN '已拒绝' WHEN 'ARCHIVED' THEN '已归档' WHEN 'CANCELLED' THEN '已取消' ELSE c.status END AS statusDesc, u.nickname AS salesName, approver.nickname AS approverName, c.approved_time AS approvedTime, c.created_time AS createdTime, c.remark FROM crm_contract c LEFT JOIN crm_customer cust ON c.customer_id = cust.id AND cust.deleted = 0 LEFT JOIN crm_order o ON c.order_id = o.id AND o.deleted = 0 LEFT JOIN sys_user u ON c.sales_id = u.id LEFT JOIN sys_user approver ON c.approved_by = approver.id WHERE c.deleted = 0
AND c.contract_no LIKE CONCAT('%', #{query.contractNo}, '%')
AND c.contract_type = #{query.contractType}
AND cust.company_name LIKE CONCAT('%', #{query.customerName}, '%')
AND c.status = #{query.status}
ORDER BY c.created_time DESC
